head.b:skin:
/* Blogger Reset */
#header-wrapper, #sidebar-wrapper, .footer-outer, .tabs-outer, .main-cap-top, .comments, .post-footer, .post-labels { display:none !important; }
body { margin: 0; padding: 0; background: #f8fafc; font-family: 'Inter', sans-serif; direction: rtl; }
.status-msg-wrap { display: none !important; }
#root { min-height: 100vh; }

/* Custom Scrollbar */
::-webkit-scrollbar { width: 8px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: #cbd5e1; border-radius: 10px; }
::-webkit-scrollbar-thumb:hover { background: #94a3b8; }

/* Animations */
@keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
.animate-fade-in { animation: fadeIn 0.4s ease-out forwards; }
@keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }

